<template>
  <el-dropdown class="table-handle-dropdown" trigger="click" @command="setTableDensity">
    <el-tooltip content="密度" effect="dark" placement="top">
      <el-icon class="pointer m-r-xs tooltip-icon" :size="18">
        <operation />
      </el-icon>
    </el-tooltip>
    <template #dropdown>
      <el-dropdown-menu>
        <el-dropdown-item
          v-for="item in [
            { label: '正常', value: 'small' },
            { label: '紧凑', value: 'mini' },
            { label: '宽松', value: 'medium' },
          ]"
          :key="item.label"
          :class="{ active: tableSize === item.value }"
          :command="item.value"
        >
          {{ item.label }}
        </el-dropdown-item>
      </el-dropdown-menu>
    </template>
  </el-dropdown>
</template>

<script lang="ts">
import { reactive, toRefs, defineComponent } from 'vue';

export default defineComponent({
  name: 'TDensityButton',
  /*
   * props: {
   * },
   */
  emits: ['table-size-change'],
  setup(props, { emit }) {
    // 响应式数据
    const state = reactive({
      // 表格尺寸
      tableSize: 'mini',
    });

    /**
     * 设置表格尺寸（密度）
     * @param command 表格尺寸（密度）
     */
    const setTableDensity = (command: string) => {
      state.tableSize = command;
      // 发送事件，告诉父组件表单尺寸改变了
      emit('table-size-change', state.tableSize);
    };

    return {
      ...toRefs(state),
      setTableDensity,
    };
  },
});
</script>
