<template>
  <div class="form-list-container" :class="{ 'close-theme-color-header': closeThemeColorHeader }">
    <!-- 表格操作列 -->
    <el-row
      v-if="showOperationColumn"
      align="middle"
      justify="space-between"
      type="flex"
      class="m-b-sm"
    >
      <!-- 左侧按钮组（密度、全屏） -->
      <el-col :span="8" class="flex">
        <!-- 表格密度设置按钮 -->
        <t-density-button v-if="showTableLeftBtn.densityBtn" @table-size-change="setTableDensity"></t-density-button>
        <!-- 表格全屏设置按钮 -->
        <t-full-screen-button v-if="showTableLeftBtn.fullScreenBtn" @full-screen-change="handleSetFullScreen"></t-full-screen-button>
        <!-- 表格标题 -->
        <slot name="tableTitleSlot"></slot>
      </el-col>

      <!-- 右侧按钮组 -->
      <el-col :span="16">
        <div class="flex flex-end">
          <!-- 表格按钮组 - 插槽 -->
          <slot name="tableBtnSlot"></slot>
        </div>
      </el-col>
    </el-row>

    <!-- 表格 -->
    <vxe-table
      ref="xTable"
      :size="tableSize"
      border
      :stripe="openStripe"
      show-overflow
      :row-config="{isHover: true}"
      :seq-config="{seqMethod:setSeqStartIndex}"
      :column-config="{resizable: true}"
      :scroll-x="{oSize: 60}"
      v-bind="$attrs"
      @sort-change="onSortChange"
      @checkbox-change="onSelectChange"
      @checkbox-all="onSelectChange"
      :header-cell-class-name="tableClassName"
    >
      <!-- 选择列（多选按钮） -->
      <vxe-column
        v-if="openSelectColumn"
        type="checkbox"
        width="48"
        align="center"
        fixed="left"
        :resizable="false"
      ></vxe-column>

      <!-- 序号列 -->
      <vxe-column
        v-if="openIndexColumn && pageSize && pageNum"
        type="seq"
        title="序号"
        :width="orderNoWidth"
        fixed="left"
        align="center"
        :resizable="false"
      >
      </vxe-column>

      <!-- 普通列 -->
      <template v-for="(tOptions, tIndex) of tableNormalOptions" :key="tIndex">
        <!-- 单表头 -->
        <vxe-column
          v-if="!tOptions.child"
          :key="tIndex"
          :title="tOptions.label"
          :field="tOptions.prop"
          :width="tOptions.width ? tOptions.width : ''"
          :min-width="tOptions.minWidth ? tOptions.minWidth : ''"
          :header-align="tOptions.headerAlign ? tOptions.headerAlign : 'center'"
          :align="tOptions.align ? tOptions.align : 'center'"
          :fixed="tOptions.fixed ? tOptions.fixed : ''"
          :sortable="tOptions.sortable ? true : false"
          :sort-by="tOptions.sortable ? tOptions.sortable : ''"
          :resizable="tOptions.resizable !== null ? tOptions.resizable : true"
        >
          <!-- 自定义列内容格式 -->
          <template v-if="tOptions.slot" #default="scope">
            <slot :name="tOptions.slot" :scope="scope"></slot>
          </template>
          <!-- 默认展示格式(此处做了判空处理, 如果为空, 则展示小短横线) -->
          <template v-else #default="scope">
            {{ `${isNoVal(scope.row[tOptions.prop])}` }}
          </template>
        </vxe-column>

        <!-- 多表头 -->
        <vxe-colgroup
          v-else
          :title="tOptions.label"
          :header-align="tOptions.headerAlign ? tOptions.headerAlign : 'center'"
        >
          <vxe-column
            v-for="(childOptions, cIndex) of tOptions.child"
            :key="cIndex"
            :title="childOptions.label"
            :field="childOptions.prop"
            :width="childOptions.width ? childOptions.width : ''"
            :min-width="childOptions.minWidth ? childOptions.minWidth : ''"
            :header-align="childOptions.headerAlign ? childOptions.headerAlign : 'center'"
            :align="childOptions.align ? childOptions.align : 'center'"
            :fixed="childOptions.fixed ? childOptions.fixed : ''"
            :sortable="childOptions.sortable ? true : false"
            :sort-by="childOptions.sortable ? childOptions.sortable : ''"
            :resizable="childOptions.resizable !== null ? childOptions.resizable : true"
          >
            <!-- 自定义列内容格式 -->
            <template v-if="childOptions.slot" #default="scope">
              <slot :name="childOptions.slot" :scope="scope"></slot>
            </template>
            <!-- 默认展示格式(此处做了判空处理, 如果为空, 则展示小短横线) -->
            <template v-else #default="scope">
              {{ `${isNoVal(scope.row[childOptions.prop])}` }}
            </template>
          </vxe-column>
        </vxe-colgroup>
      </template>

      <!-- 操作列 -->
      <vxe-column
        v-if="tableActionOptions"
        :width="tableActionOptions.width ? tableActionOptions.width : ''"
        :min-width="tableActionOptions.minWidth ? tableActionOptions.minWidth : ''"
        title="操作"
        fixed="right"
        align="center"
        :resizable="false"
      >
        <template #default="scope">
          <slot :name="'actionSolt'" :scope="scope"></slot>
        </template>
      </vxe-column>
    </vxe-table>
  </div>

  <!-- <span>表格组件接收到的 $attrs: {{ $attrs }}</span> -->
</template>

<script lang="ts">
import { reactive, toRefs, defineComponent, PropType, computed, ref, watch } from 'vue';
// 表格密度设置按钮组件
import TDensityButton from './t-density-button.vue';
// 表格全屏设置按钮
import TFullScreenButton from './t-full-screen-button.vue';

export default defineComponent({
  name: 'TTableMega',
  components: {
    TDensityButton, // 表格密度设置按钮组件
    TFullScreenButton, // 表格全屏设置按钮
  },
  inheritAttrs: true,
  props: {
    // 表格数据
    tableData: {
      type: Array,
      required: true,
      default: () => [],
    },
    // 表头配置项
    tableHeaderOpitons: {
      type: Array as PropType<CommonBaseCrud.TableHeaderOptions[]>,
      required: true,
      default: () => [],
    },
    // 页码
    pageNum: {
      type: Number,
      default: 1,
    },
    // 每页条数
    pageSize: {
      type: Number,
      default: 10,
    },
    // 是否开启序号列(开启的话,必须传入每页条数/页码)
    openIndexColumn: {
      type: Boolean,
      default: false,
    },
    // 是否开启选择列
    openSelectColumn: {
      type: Boolean,
      default: false,
    },
    // 操作列是否显示
    showOperationColumn: {
      type: Boolean,
      default: true,
    },
    // 表格顶部左侧列显隐控制
    showTableLeftBtn: {
      type: Object,
      default: () => ({
        densityBtn: true,
        fullScreenBtn: true,
      }),
    },
    // 是否开启斑马纹
    openStripe: {
      type: Boolean,
      default: true,
    },
    // 关闭表头背景色是否根据主题色变化
    closeThemeColorHeader: {
      type: Boolean,
      default: false,
    },
    // 序号列宽度
    orderNoWidth: {
      type: String,
      default: '52',
    },
    // 是否禁用当前页面的多选框
    isDisableSelectionAll: {
      type: Boolean,
      default: false,
    },
  },
  emits: ['table-sort-change', 'table-choose-change', 'update:fullScreen'],
  setup(props, { emit }) {
    // 响应式数据
    const state = reactive({
      // 用户选择的列表项数组
      multipleSelection: [] as any,
      // 表格尺寸
      tableSize: 'mini',
      // 是否全屏
      fullScreen: false,
      // 列表类名
      tableClassName:'',
    });

    // 过滤 操作项 之后的列配置
    const tableNormalOptions = computed(() => props.tableHeaderOpitons.filter((item) => !item.action));
    // 操作项列配置
    const tableActionOptions = computed(() => props.tableHeaderOpitons.find((item) => item.action));

    /*
     * console.log('过滤 操作项 之后的配置', tableNormalOptions.value);
     * console.log('操作项', tableActionOptions.value);
     */

    /**
     * 表格排序
     * @param sortColumn
     */
    const onSortChange = (sortColumn: CommonBaseCrud.TableSortColumn) => {
      let orderBy = '';
      if (sortColumn && sortColumn.column && sortColumn.column.sortBy && sortColumn.order) {
        orderBy = `${sortColumn.column.sortBy} ${sortColumn.order.replace('ending', '')}`;
      } else {
        orderBy = '';
      }
      emit('table-sort-change', orderBy);
    };

    /**
     * 表格多选改变
     * @description 当选择多条表格数据时，被选中的数据会被存储到 state 响应数据中去
     * @param val 当前选中的全部表格数据（以数组的形式进行存储）
     */
    const onSelectChange = (val: any) => {
      if (Array.isArray(val)) {
        state.multipleSelection = val;
      } else {
        state.multipleSelection = val.records;
      }
      emit('table-choose-change', state.multipleSelection);
    };

    /**
     * 设置表格尺寸（密度）
     * @param command 表格尺寸（密度）
     */
    const setTableDensity = (command: string) => {
      state.tableSize = command;
    };

    /**
     * 控制全屏状态
     */
    const handleSetFullScreen = (val: any) => {
      state.fullScreen = val;
      emit('update:fullScreen', val);
    };

    /**
     * 是否有值
     */
    const isNoVal = (val?: any) => {
      let newVal = val;
      if (!val && val !== 0) {
        newVal = '-';
      }
      return newVal;
    };

    const xTable = ref({} as any);

    // 监听数据的变化，重新加载数据
    watch(() => props.tableData, () => {
      const tableRef = xTable.value;
      if (tableRef) {
        tableRef.loadData(props.tableData);
      }
    }, {
      deep: true,
    });

    /**
     * @description: 设置序列号的值
     * @param {*} data 单条数据
     * @return {*}返回处理后的值
     */
    const setSeqStartIndex = (data: { rowIndex: number; }) => {
      const { rowIndex } = data;
      return (props.pageNum - 1) * props.pageSize + rowIndex + 1;
    };

    // 设置列表全选是否禁用
    watch(() => props.isDisableSelectionAll, () => {
      if(props.isDisableSelectionAll) {
          state.tableClassName = 'disable-selection';
        } else {
          state.tableClassName = '';
        }
      },
      {
        immediate: true,
      }
    )

    return {
      ...toRefs(state),
      tableNormalOptions,
      tableActionOptions,
      isNoVal,
      onSortChange,
      onSelectChange,
      setTableDensity,
      handleSetFullScreen,
      xTable,
      setSeqStartIndex,
    };
  },
});
</script>

<style lang="scss" scoped>
.flex {
  display: flex;
}

</style>
