<template>
  <div class="form-list-container" :class="{ 'close-theme-color-header': closeThemeColorHeader }">
    <!-- 表格操作列 -->
    <el-row
      v-if="showOperationColumn"
      align="middle"
      justify="space-between"
      type="flex"
      class="m-b-sm"
    >
      <!-- 左侧按钮组（密度、全屏） -->
      <el-col :span="8" class="flex">
        <!-- 表格密度设置按钮 -->
        <t-density-button v-if="showTableLeftBtn.densityBtn" @table-size-change="setTableDensity"></t-density-button>
        <!-- 表格全屏设置按钮 -->
        <t-full-screen-button
          v-if="showTableLeftBtn.fullScreenBtn"
          @full-screen-change="handleSetFullScreen"
        ></t-full-screen-button>
        <!-- 表格标题 -->
        <slot name="tableTitleSlot"></slot>
      </el-col>

      <!-- 右侧按钮组 -->
      <el-col :span="16">
        <div class="flex flex-end">
          <!-- 表格按钮组 - 插槽 -->
          <slot name="tableBtnSlot"></slot>
        </div>
      </el-col>
    </el-row>

    <!-- 表格 -->
    <el-table
      ref="tableRef"
      :data="tableData"
      :cell-style="changeCellStyle"
      :size="tableSize"
      tooltip-effect="dark"
      sortable
      border
      :stripe="openStripe"
      class="table-component"
      v-bind="$attrs"
      @selection-change="onSelectChange"
      @sort-change="onSortChange"
      :header-cell-class-name="tableClassName"
    >
      <!-- 选择列（多选按钮） -->
      <el-table-column
        v-if="openSelectColumn"
        :type="'selection'"
        :header-align="'center'"
        :align="'center'"
        :fixed="'left'"
        :selectable="selectable"
        :resizable="false"
      ></el-table-column>

      <!-- 序号列 -->
      <el-table-column
        v-if="openIndexColumn && pageSize && pageNum"
        :type="'index'"
        :align="'center'"
        :fixed="'left'"
        :label="'序号'"
        :width="orderNoWidth"
        :min-width="orderNoWidth"
        :resizable="false"
      >
        <template #default="scope">
          <span>{{ (pageNum - 1) * pageSize + scope.$index + 1 }}</span>
        </template>
      </el-table-column>

      <!-- 普通列 -->
      <template v-for="(tOptions, tIndex) of tableNormalOptions" :key="tIndex" :header-align="'center'">
        <!-- 单表头 -->
        <el-table-column
          v-if="!tOptions.child"
          :key="tIndex"
          :prop="tOptions.prop"
          :label="tOptions.label"
          :width="tOptions.width ? tOptions.width : ''"
          :min-width="tOptions.minWidth ? tOptions.minWidth : ''"
          :align="tOptions.align ? tOptions.align : 'center'"
          :header-align="tOptions.headerAlign ? tOptions.headerAlign : 'center'"
          :fixed="tOptions.fixed ? tOptions.fixed : false"
          :sortable="tOptions.sortable ? tOptions.sortable : false"
          :show-overflow-tooltip="tOptions.slot ? false : true"
          :resizable="tOptions.resizable !== null ? tOptions.resizable : true"
        >
          <!-- 自定义列内容格式 -->
          <template v-if="tOptions.slot" #default="scope">
            <slot :name="tOptions.slot" :scope="scope"></slot>
          </template>
          <!-- 默认展示格式(此处做了判空处理, 如果为空, 则展示小短横线) -->
          <template v-else #default="scope">
            {{ `${isNoVal(scope.row[tOptions.prop])}` }}
          </template>
        </el-table-column>

        <!-- 多表头 -->
        <el-table-column v-else :label="tOptions.label" :header-align="'center'">
          <el-table-column
            v-for="(childOptions, cIndex) of tOptions.child"
            :key="cIndex"
            :prop="childOptions.prop"
            :label="childOptions.label"
            :width="childOptions.width ? childOptions.width : ''"
            :min-width="childOptions.minWidth ? childOptions.minWidth : ''"
            :align="childOptions.align ? childOptions.align : 'center'"
            :header-align="childOptions.headerAlign ? childOptions.headerAlign : 'center'"
            :sortable="childOptions.sortable ? childOptions.sortable : false"
            :show-overflow-tooltip="childOptions.slot ? false : true"
            :resizable="childOptions.resizable !== null ? childOptions.resizable : true"
          >
            <!-- 自定义列内容格式 -->
            <template v-if="childOptions.slot" #default="scope">
              <slot :name="childOptions.slot" :scope="scope"></slot>
            </template>
            <!-- 默认展示格式(此处做了判空处理, 如果为空, 则展示小短横线) -->
            <template v-else #default="scope">
              {{ `${isNoVal(scope.row[childOptions.prop])}` }}
            </template>
          </el-table-column>
        </el-table-column>
      </template>

      <!-- 操作列 -->
      <el-table-column
        v-if="tableActionOptions"
        :width="tableActionOptions.width ? tableActionOptions.width : ''"
        :min-width="tableActionOptions.minWidth ? tableActionOptions.minWidth : ''"
        :header-align="'center'"
        :align="'center'"
        :fixed="tableActionOptions.fixed ? tableActionOptions.fixed : 'right'"
        label="操作"
        :resizable="false"
      >
        <template #default="scope">
          <slot :name="'actionSolt'" :scope="scope"></slot>
        </template>
      </el-table-column>
    </el-table>
  </div>

  <!-- <span>表格组件接收到的 $attrs: {{ $attrs }}</span> -->
</template>

<script lang="ts">
import { reactive, toRefs, defineComponent, PropType, computed, onMounted, ref, watch } from 'vue';
// 表格密度设置按钮组件
import TDensityButton from './t-density-button.vue';
// 表格全屏设置按钮
import TFullScreenButton from './t-full-screen-button.vue';

export default defineComponent({
  name: 'TTable',
  components: {
    TDensityButton, // 表格密度设置按钮组件
    TFullScreenButton, // 表格全屏设置按钮
  },
  inheritAttrs: true,
  props: {
    // 表格数据
    tableData: {
      type: Array,
      required: true,
      default: () => [],
    },
    // 表头配置项
    tableHeaderOpitons: {
      type: Array as PropType<CommonBaseCrud.TableHeaderOptions[]>,
      required: true,
      default: () => [],
    },
    // 判断是否禁用多选方法（返回true不禁用）
    selectable: {
      type: Function,
      default: (row: any, index: number) => true,
    },
    // 页码
    pageNum: {
      type: Number,
      default: 1,
    },
    // 每页条数
    pageSize: {
      type: Number,
      default: 10,
    },
    // 是否开启序号列(开启的话,必须传入每页条数/页码)
    openIndexColumn: {
      type: Boolean,
      default: false,
    },
    // 是否开启选择列
    openSelectColumn: {
      type: Boolean,
      default: false,
    },
    // 要修改背景的列 index 数组
    changeBgColumnIndex: {
      type: Array,
      default: () => [],
    },
    // 要修改的背景色
    changeBgColumnColor: {
      type: String,
      default: '#F5F7FA',
    },
    // 操作列是否显示
    showOperationColumn: {
      type: Boolean,
      default: true,
    },
    // 表格顶部左侧列显隐控制
    showTableLeftBtn: {
      type: Object,
      default: () => ({
        densityBtn: true,
        fullScreenBtn: true,
      }),
    },
    // 是否开启斑马纹
    openStripe: {
      type: Boolean,
      default: true,
    },
    // 关闭表头背景色是否根据主题色变化
    closeThemeColorHeader: {
      type: Boolean,
      default: false,
    },
    // 序号列宽度
    orderNoWidth: {
      type: Number,
      default: 55,
    },
    // 是否禁用当前页面的多选框
    isDisableSelectionAll: {
      type: Boolean,
      default: false,
    },
  },
  emits: ['table-sort-change', 'table-choose-change', 'update:fullScreen'],
  setup(props, { emit }) {
    // 响应式数据
    const state = reactive({
      // 用户选择的列表项数组
      multipleSelection: [] as any,
      // 表格尺寸
      tableSize: 'mini',
      // 是否全屏
      fullScreen: false,
      // 列表类名
      tableClassName:'',
    });

    const tableRef = ref();

    // 过滤 操作项 之后的列配置
    const tableNormalOptions = computed(() => props.tableHeaderOpitons.filter((item) => !item.action));
    // 操作项列配置
    const tableActionOptions = computed(() => props.tableHeaderOpitons.find((item) => item.action));

    /*
     * console.log('过滤 操作项 之后的配置', tableNormalOptions.value);
     * console.log('操作项', tableActionOptions.value);
     */

    /**
     * 改变表格列背景色
     * @param column 表格单元格的 style 的回调方法接受的数据
     */
    const changeCellStyle = (column: CommonBaseCrud.TableColumn) => {
      if (props.changeBgColumnIndex && props.changeBgColumnIndex.includes(column.columnIndex)) {
        // console.log(column);
        return `background-color: ${props.changeBgColumnColor}`;
      }
      return null;
    };

    /**
     * 表格排序
     * @param sortColumn
     */
    const onSortChange = (sortColumn: CommonBaseCrud.TableSortColumn) => {
      let orderBy = '';
      if (sortColumn && sortColumn.column && sortColumn.column.sortable) {
        orderBy = `${sortColumn.column.sortable} ${sortColumn.order.replace('ending', '')}`;
      } else {
        orderBy = '';
      }
      emit('table-sort-change', orderBy);
    };

    /**
     * 表格多选改变
     * @description 当选择多条表格数据时，被选中的数据会被存储到 state 响应数据中去
     * @param val 当前选中的全部表格数据（以数组的形式进行存储）
     */
    const onSelectChange = (val: any) => {
      state.multipleSelection = val;
      emit('table-choose-change', state.multipleSelection);
    };

    /**
     * element计算的高度，没有带上小数，导致边框线被压着，这里重新设置一下
     */
    const setTableBodyTop = () => {
      setTimeout(() => {
        const tableDom = document.getElementsByClassName('el-table') as any;
        if (tableDom && tableDom.length > 0) {
          for (let i = 0; i < tableDom.length; i++) {
            // 获取高度
            const tableHeaderDom = tableDom[i].getElementsByClassName('el-table__header-wrapper')[0];
            const tableHeaderHeight = tableHeaderDom.getBoundingClientRect().height + 'px';
            // 设置top值
            const tableBody = tableDom[i].getElementsByClassName('el-table__fixed-body-wrapper');
            if (tableBody && tableBody[0]) {
              tableBody[0].style.top = tableHeaderHeight;
            }
            if (tableBody && tableBody[1]) {
              tableBody[1].style.top = tableHeaderHeight;
            }
            const tablePatch = tableDom[i].getElementsByClassName('el-table__fixed-right-patch');
            if (tablePatch && tablePatch[0]) {
              tablePatch[0].style.height = tableHeaderHeight;
            }
          }
        }
      }, 200);
    };

    /**
     * 设置表格尺寸（密度）
     * @param command 表格尺寸（密度）
     */
    const setTableDensity = (command: string) => {
      state.tableSize = command;
      setTableBodyTop();
    };

    /**
     * 控制全屏状态
     */
    const handleSetFullScreen = (val: any) => {
      state.fullScreen = val;
      emit('update:fullScreen', val);
    };

    /**
     * 是否有值
     */
    const isNoVal = (val?: any) => {
      let newVal = val;
      if (!val && val !== 0) {
        newVal = '-';
      }
      return newVal;
    };

    onMounted(() => {
      // element计算的高度，没有带上小数，导致边框线被压着，这里重新设置一下
      setTableBodyTop();
    });

    // 设置列表全选是否禁用
    watch(() => props.isDisableSelectionAll, () => {
        if(props.isDisableSelectionAll) {
          state.tableClassName = 'disable-selection';
        } else {
          state.tableClassName = '';
        }
      },
      {
        immediate: true,
      }
    )

    /*
     * 表头背景是否根据主题色变化
     * watch(
     *   () => props.closeThemeColorHeader,
     *   (val) => {
     *     const themeName = JSON.parse(localStorage.getItem('userStyle') || '{}').theme ?? '';
     *     console.log('在表格中，获取主题色 ===', themeName);
     *     if (val && themeName) {
     *       document.body.style.setProperty(
     *         '--table-header-background-color',
     *         `var(--thead-${themeName}-background)`,
     *       );
     *     } else {
     *       document.body.style.setProperty('--table-header-background-color', 'var(--thead-background)');
     *     }
     *   },
     *   {
     *     immediate: true,
     *   },
     * );
     */

    return {
      ...toRefs(state),
      tableNormalOptions,
      tableActionOptions,
      tableRef,
      isNoVal,
      changeCellStyle,
      onSortChange,
      onSelectChange,
      setTableDensity,
      handleSetFullScreen,
      // cellClass,
    };
  },
});
</script>

<style lang="scss" scoped>
.table-component {
  width: 100%;
}

.flex {
  display: flex;
}

</style>
